// // This module calculates the quotient and remainder of two 2-bit numbers, but it does not handle division by zero correctly.
module two_bit_divider(input [1:0] A, input [1:0] B, output reg [1:0] Q, output reg [1:0] R);  
    always @(*) begin  
        if (B == 2'b00) begin  
            Q = 2'b00;  
            R = 2'b00;  
        end else begin  
            Q = A / B;  
            R = A % B;  
        end  
    end  
endmodule
